1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const FIRST_INSURANCE_PERCENT = 110;
13	const PROCESSING_FEE = 5;
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	type Customer = { name: string; years: number; contracts: number };
17	
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const LOYALTY_DISCOUNT_RATE = 0.2;
20	
21	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
22	const BLOCK_OF_3_BASE_PREMIUM = 60;
23	const BLOCK_OF_3_SIZE = 3;
24	const CURSED_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	
28	const isBlockOf3Components = (type: string, count: number): boolean =>
29	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
30	
31	const baseForGroup = (type: string, count: number): number =>
32	  isBlockOf3Components(type, count)
33	    ? BLOCK_OF_3_BASE_PREMIUM
34	    : BASE_PREMIUMS[type] * count;
35	
36	const countItemsByType = (items: Item[]): Record<string, number> =>
37	  items.reduce<Record<string, number>>((counts, item) => {
38	    counts[item.type] = (counts[item.type] ?? 0) + 1;
39	    return counts;
40	  }, {});
41	
42	const baseTotalFor = (items: Item[]): number =>
43	  Object.entries(countItemsByType(items))
44	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
45	
46	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
47	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
48	
49	const cursedSurchargeFor = (item: Item): number =>
50	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
51	
52	const highEnchantmentSurchargeFor = (item: Item): number =>
53	  surchargeOnBase(item, (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
54	
55	const itemSurchargesFor = (items: Item[]): number =>
56	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
57	
58	const loyaltyDiscountFor = (customer: Customer, baseTotal: number): number =>
59	  customer.years >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
60	
61	const applyFirstInsurance = (baseTotal: number): number =>
62	  (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
63	
64	const quotePremium = (items: Item[], customer: Customer): number => {
65	  const baseTotal = baseTotalFor(items);
66	  const policyBase = applyFirstInsurance(baseTotal);
67	  const itemSurcharges = itemSurchargesFor(items);
68	  const loyaltyDiscount = loyaltyDiscountFor(customer, baseTotal);
69	  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount + PROCESSING_FEE);
70	};
71	
72	export function processScenario(scenario: any): unknown {
73	  const [{ items }] = scenario.steps;
74	  return { results: [{ premium: quotePremium(items, scenario.customer) }] };
75	}
